// GOOD: sync path, no alloc
public async ValueTask<User?> GetUserAsync(int id, CancellationToken ct = default) {
    if (_cache.TryGetValue(id, out var cached)) return cached;
    var user = await _db.Users.FindAsync([id], ct);
    _cache[id] = user;
    return user;
}

// WRONG: double await - undefined behavior!
var vt = GetUserAsync(1);
var u1 = await vt;
var u2 = await vt; // BUG

// RIGHT: convert sang Task nếu multi-await
Task<User?> task = GetUserAsync(1).AsTask();
var u1 = await task;
var u2 = await task; // OK
